// ============================================================
// Recevoir les données du PublicationAgent
// Contrat entrée: { job, payload, access_token, channel_name,
//   diffusion_type, correlation_id, job_id }
// ============================================================
const input = $input.first().json;
const dt = input.diffusion_type;

if (!['ORGANIC', 'PAID'].includes(dt)) {
  // Retour structuré au lieu de throw — compatible PublicationAgent
  return [{ json: {
    _success: false,
    _status: 'FAILED_PUBLICATION',
    _error_code: 'INVALID_DIFFUSION_TYPE',
    _error_message: `diffusion_type inconnu: ${dt}`,
    _orphans: {},
    job_id: input.job_id || null,
    correlation_id: input.correlation_id || '',
    _route: 'ERROR'
  } }];
}

return [{ json: { ...input, _route: dt } }];

// ============================================================
// FB ORGANIC — Construction requête (UC-03 §6.1)
// Supporte : texte, image, vidéo, planification native
// ============================================================
const d = $('Initialiser Connecteur').first().json;
const payload = d.payload;
const content = payload.content;
const pp = payload.platform_params;
const page_id = pp.page_id;

const hasMedia = content.media && content.media.length > 0;
const mediaItem = hasMedia ? content.media[0] : null;
const mediaType = mediaItem ? (mediaItem.type || '').toUpperCase() : null;

// Composer le message avec hashtags
let message = content.text || '';
if (content.hashtags && Array.isArray(content.hashtags) && content.hashtags.length > 0) {
  message += '\n\n' + content.hashtags.join(' ');
}

let endpoint, body, description;

if (hasMedia && (mediaType === 'IMAGE' || mediaType === 'PHOTO')) {
  // ──── POST /{page_id}/photos ────
  endpoint = `https://graph.facebook.com/v21.0/${page_id}/photos`;
  body = { url: mediaItem.url, caption: message, published: true };
  if (mediaItem.alt_text) body.alt_text_custom = mediaItem.alt_text;
  description = 'FB ORGANIC Photo';

} else if (hasMedia && (mediaType === 'VIDEO' || mediaType === 'REEL')) {
  // ──── POST /{page_id}/videos ────
  endpoint = `https://graph.facebook.com/v21.0/${page_id}/videos`;
  body = { file_url: mediaItem.url, description: message, published: true };
  if (content.headline) body.title = content.headline;
  description = 'FB ORGANIC Video';

} else {
  // ──── POST /{page_id}/feed (texte seul ou lien) ────
  endpoint = `https://graph.facebook.com/v21.0/${page_id}/feed`;
  body = { message };
  if (content.link && content.link.url) body.link = content.link.url;
  description = 'FB ORGANIC Post';
}

// ──── Planification native Facebook (10min – 75j) ────
if (d.job && d.job.scheduled_at) {
  const scheduledTs = Math.floor(new Date(d.job.scheduled_at).getTime() / 1000);
  const now = Math.floor(Date.now() / 1000);
  const minFuture = now + 600;       // 10 min minimum
  const maxFuture = now + 6480000;   // 75 jours maximum
  if (scheduledTs > minFuture && scheduledTs < maxFuture) {
    body.published = false;
    body.scheduled_publish_time = scheduledTs;
  }
}

return [{ json: {
  ...d,
  _endpoint: endpoint,
  _body: body,
  _description: description
} }];

// ============================================================
// Traiter la réponse Facebook ORGANIC
// onError: continueRegularOutput → on reçoit toujours une sortie
// ============================================================
const resp = $input.first().json;
const prev = $('Construire requête ORGANIC').first().json;

// Succès : Facebook retourne { id: "..." }
if (resp.id) {
  return [{ json: {
    _success: true,
    _platform_post_id: String(resp.id),
    _status: 'PUBLISHED',
    _error_code: null,
    _error_message: null,
    _orphans: {},
    job_id: prev.job_id,
    correlation_id: prev.correlation_id
  } }];
}

// Échec : erreur Facebook ou erreur réseau
const fbErr = resp.error || {};
const errMsg = typeof fbErr === 'object'
  ? (fbErr.message || JSON.stringify(fbErr))
  : String(fbErr);
const errCode = fbErr.code ? `META_${fbErr.code}` : 'HTTP_ERROR';

return [{ json: {
  _success: false,
  _status: 'FAILED_PUBLICATION',
  _error_code: errCode,
  _error_message: String(errMsg).substring(0, 500),
  _orphans: {},
  job_id: prev.job_id,
  correlation_id: prev.correlation_id
} }];

// ============================================================
// FB PAID — Étape 1 : Valider ad_account_id + Préparer Campaign
// CORRECTION v2 : ad_account_id EXPLICITE obligatoire
// (suppression du fallback dangereux page_id → ad_account_id)
// ============================================================
const d = $('Initialiser Connecteur').first().json;
const payload = d.payload;
const ads = payload.ads;
const pp = payload.platform_params;

// ──── Exiger ad_account_id explicite ────
const account_id = pp.ad_account_id || pp.account_id;
if (!account_id) {
  return [{ json: {
    ...d, _step_ok: false,
    _error_code: 'MISSING_AD_ACCOUNT_ID',
    _error_message: 'ad_account_id absent dans platform_params. Requis pour PAID.',
    _orphans: {}
  } }];
}

const campaignBody = {
  name: `${d.job.campaign_id || 'Campaign'} — FACEBOOK — ${d.job_id}`,
  objective: ads?.campaign_params?.objective || 'OUTCOME_TRAFFIC',
  buying_type: ads?.campaign_params?.buying_type || 'AUCTION',
  status: 'PAUSED',
  special_ad_categories: ads?.campaign_params?.special_ad_categories || []
};

return [{ json: {
  ...d,
  _account_id: account_id,
  _step_ok: true,
  _step: 'CAMPAIGN',
  _endpoint: `https://graph.facebook.com/v21.0/act_${account_id}/campaigns`,
  _body: campaignBody,
  _orphans: {}
} }];

// ============================================================
// Vérifier réponse Campaign → Préparer Ad Set
// ============================================================
const resp = $input.first().json;
const prev = $('PAID 1 — Validate + Prép Campaign').first().json;

if (!resp.id) {
  const fbErr = resp.error || {};
  return [{ json: {
    ...prev, _step_ok: false,
    _error_code: 'CAMPAIGN_CREATION_FAILED',
    _error_message: (fbErr.message || JSON.stringify(fbErr)).substring(0, 500),
    _orphans: {}
  } }];
}

const meta_campaign_id = String(resp.id);
const ads = prev.payload.ads || {};
const budget = prev.job.budget_amount ? prev.job.budget_amount * 100 : null;

if (!budget || budget <= 0) {
  return [{ json: {
    ...prev, _step_ok: false,
    _meta_campaign_id: meta_campaign_id,
    _error_code: 'INVALID_BUDGET',
    _error_message: 'budget_amount invalide ou absent',
    _orphans: { meta_campaign_id }
  } }];
}

const adsetBody = {
  name: `AdSet — ${prev.job.campaign_id || 'AdSet'} — ${prev.job_id}`,
  campaign_id: meta_campaign_id,
  daily_budget: budget,
  billing_event: 'IMPRESSIONS',
  bid_strategy: ads.adset_params?.bid_strategy || 'LOWEST_COST_WITHOUT_CAP',
  targeting: ads.adset_params?.targeting || { geo_locations: { countries: ['MA'] } },
  publisher_platforms: ads.adset_params?.placements || ['facebook'],
  facebook_positions: ads.adset_params?.positions || ['feed'],
  status: 'PAUSED'
};

if (prev.job.scheduled_at) adsetBody.start_time = prev.job.scheduled_at;

return [{ json: {
  ...prev,
  _meta_campaign_id: meta_campaign_id,
  _orphans: { meta_campaign_id },
  _step_ok: true,
  _step: 'ADSET',
  _endpoint: `https://graph.facebook.com/v21.0/act_${prev._account_id}/adsets`,
  _body: adsetBody
} }];

// ============================================================
// Vérifier réponse Ad Set → Préparer Ad (Creative)
// ============================================================
const resp = $input.first().json;
const prev = $('PAID 2 — Check Campaign + Prép AdSet').first().json;

if (!resp.id) {
  const fbErr = resp.error || {};
  return [{ json: {
    ...prev, _step_ok: false,
    _error_code: 'ADSET_CREATION_FAILED',
    _error_message: (fbErr.message || JSON.stringify(fbErr)).substring(0, 500)
  } }];
}

const meta_adset_id = String(resp.id);
const content = prev.payload.content;
const pp = prev.payload.platform_params;

const creative = {
  object_story_spec: {
    page_id: pp.page_id,
    link_data: {
      message: content.text || '',
      link: content.link?.url || '',
      name: content.headline || '',
      description: content.description || '',
      call_to_action: {
        type: pp.cta_type || 'LEARN_MORE',
        value: { link: content.link?.url || '' }
      }
    }
  }
};
if (content.media && content.media[0]) {
  creative.object_story_spec.link_data.image_url = content.media[0].url;
}

const adBody = {
  name: `Ad — ${prev.job.campaign_id || 'Ad'} — ${prev.job_id}`,
  adset_id: meta_adset_id,
  status: 'ACTIVE',
  creative
};

return [{ json: {
  ...prev,
  _meta_adset_id: meta_adset_id,
  _orphans: { meta_campaign_id: prev._meta_campaign_id, meta_adset_id },
  _step_ok: true,
  _step: 'AD',
  _endpoint: `https://graph.facebook.com/v21.0/act_${prev._account_id}/ads`,
  _body: adBody
} }];

// ============================================================
// Vérifier réponse Ad → Préparer Activation Campaign
// ============================================================
const resp = $input.first().json;
const prev = $('PAID 3 — Check AdSet + Prép Ad').first().json;

if (!resp.id) {
  const fbErr = resp.error || {};
  return [{ json: {
    ...prev, _step_ok: false,
    _error_code: 'AD_CREATION_FAILED',
    _error_message: (fbErr.message || JSON.stringify(fbErr)).substring(0, 500)
  } }];
}

const meta_ad_id = String(resp.id);

return [{ json: {
  ...prev,
  _meta_ad_id: meta_ad_id,
  _orphans: {
    meta_campaign_id: prev._meta_campaign_id,
    meta_adset_id: prev._meta_adset_id,
    meta_ad_id
  },
  _step_ok: true,
  _step: 'ACTIVATE',
  _endpoint: `https://graph.facebook.com/v21.0/${prev._meta_campaign_id}`,
  _body: { status: 'ACTIVE' }
} }];

// ============================================================
// Vérifier réponse Activation
// Succès = réponse { success: true } ou pas d'erreur
// ============================================================
const resp = $input.first().json;
const prev = $('PAID 4 — Check Ad + Prép Activation').first().json;

// L'activation retourne { success: true } ou une erreur
const isError = resp.error && !resp.success;
if (isError) {
  const fbErr = resp.error || {};
  return [{ json: {
    ...prev, _step_ok: false,
    _error_code: 'ACTIVATION_FAILED',
    _error_message: (fbErr.message || JSON.stringify(fbErr)).substring(0, 500)
    // Note spec: objets laissés en PAUSED, activation manuelle possible
  } }];
}

return [{ json: { ...prev, _step_ok: true } }];

// ============================================================
// Pipeline PAID complet — Construire platform_post_id composite
// ============================================================
const prev = $('PAID 4 — Check Ad + Prép Activation').first().json;
const platformPostId = [
  `meta_campaign:${prev._meta_campaign_id}`,
  `meta_adset:${prev._meta_adset_id}`,
  `meta_ad:${prev._meta_ad_id}`
].join('|');

return [{ json: {
  _success: true,
  _platform_post_id: platformPostId,
  _status: 'PUBLISHED',
  _error_code: null,
  _error_message: null,
  _orphans: {},
  job_id: prev.job_id,
  correlation_id: prev.correlation_id
} }];

// ============================================================
// CONVERGENCE ÉCHEC — toutes les branches d'erreur PAID
// Reçoit les données depuis n'importe quel Check qui échoue
// ============================================================
const d = $input.first().json;

return [{ json: {
  _success: false,
  _status: d._status || 'FAILED_PUBLICATION',
  _error_code: d._error_code || 'UNKNOWN',
  _error_message: d._error_message || 'Erreur inconnue dans le pipeline PAID',
  _orphans: d._orphans || {},
  job_id: d.job_id,
  correlation_id: d.correlation_id
} }];
